output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?date WHERE {
  ?season wdt:P154 wd:Q15728550 ; wdt:P155 1 ; wdt:P577 ?date .
}

args.sparql:
SELECT ?date WHERE { 
  ?season wdt:P154 wd:Q15728550 ;
          wdt:P155 "1" .
  ?episode wdt:P361 ?season ;
           wdt:P577 ?date .
} ORDER BY ASC(?date) LIMIT 1
